const e=document.documentElement;e.classList.remove("dark");window.toggleTheme=()=>{e.classList.toggle("dark"),localStorage.setItem("theme",e.classList.contains("dark")?"dark":"light")};const t=document.getElementById("btn-back-to-top");window.addEventListener("scroll",()=>{window.scrollY>20?t.style.display="block":t.style.display="none"});t?.addEventListener("click",()=>{window.scrollTo({top:0,behavior:"smooth"})});document.addEventListener("DOMContentLoaded",function(){const o=document.querySelector('.theme-switch input[type="checkbox"]');o&&o.addEventListener("click",()=>{document.documentElement.classList.toggle("dark"),document.documentElement.classList.contains("dark")?localStorage.setItem("theme","dark"):localStorage.setItem("theme","light")})});
